// ─── Rarity spawn weights ───────────────────────────────────────
const RARITY_WEIGHTS = {
  Common: 60, Rare: 25, Epic: 10, Legendary: 4, Exclusive: 1,
};

// ─── Type advantage: attacker → defender → multiplier ──────────
// Attack > Stamina > Defense > Attack
const TYPE_CHART = {
  Attack:  { Attack: 1.0, Defense: 0.8, Stamina: 1.3, Balance: 1.0 },
  Stamina: { Attack: 0.9, Defense: 1.3, Stamina: 1.0, Balance: 1.0 },
  Defense: { Attack: 1.3, Defense: 1.0, Stamina: 0.8, Balance: 1.0 },
  Balance: { Attack: 1.0, Defense: 1.0, Stamina: 1.0, Balance: 1.0 },
};

// ─── Ranks ─────────────────────────────────────────────────────
const RANK_TITLES = [
  { wins: 0,   title: 'Rookie Blader' },
  { wins: 10,  title: 'Apprentice Blader' },
  { wins: 25,  title: 'Rising Blader' },
  { wins: 50,  title: 'Pro Blader' },
  { wins: 100, title: 'Elite Blader' },
  { wins: 200, title: 'Master Blader' },
  { wins: 500, title: 'Legend Blader' },
];

function getRankTitle(wins) {
  let title = RANK_TITLES[0].title;
  for (const r of RANK_TITLES) { if (wins >= r.wins) title = r.title; }
  return title;
}

function getRandomBey(options = {}) {
  const { excludeExclusive = true } = options;
  const pool = Object.values(BEYS).filter(b => {
    if (excludeExclusive && b.rarity === 'Exclusive') return false;
    return true;
  });
  const totalWeight = pool.reduce((sum, b) => sum + RARITY_WEIGHTS[b.rarity], 0);
  let rand = Math.random() * totalWeight;
  for (const bey of pool) {
    rand -= RARITY_WEIGHTS[bey.rarity];
    if (rand <= 0) return bey;
  }
  return pool[0];
}

function getBeyById(id) { return BEYS[id] || null; }
function getAllBeys() { return Object.values(BEYS); }
function getTypeMultiplier(attackerType, defenderType) {
  return TYPE_CHART[attackerType]?.[defenderType] ?? 1.0;
}

module.exports = { BEYS, RARITY_WEIGHTS, TYPE_CHART, RANK_TITLES, getRankTitle, getRandomBey, getBeyById, getAllBeys, getTypeMultiplier };
